// src/pages/MasterProductListPage.js
import React, { useState, useEffect, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import './MasterProductListPage.css'; // Tạo file CSS riêng

function MasterProductListPage() {
    const navigate = useNavigate();
    const token = localStorage.getItem('token');

    const [masterData, setMasterData] = useState([]);
    const [loading, setLoading] = useState(true);
    const [filters, setFilters] = useState({
        tenCoSo: '',
        tinhThanhPho: '',
        tenLamSan: '',
        trangThai: ''
    });

    useEffect(() => {
        if (!token) navigate('/login');
        fetchMasterData();
    }, []);

    const fetchMasterData = async () => {
        setLoading(true);
        try {
            // Thay thế bằng endpoint mới từ backend
            const response = await axios.get('http://localhost:10000/api/master-product-list', {
                headers: { Authorization: `Bearer ${token}` }
            });
            setMasterData(response.data);
        } catch (err) {
            console.error("Lỗi khi tải dữ liệu tổng hợp:", err);
        } finally {
            setLoading(false);
        }
    };

    const handleFilterChange = (e) => {
        const { name, value } = e.target;
        setFilters(prev => ({ ...prev, [name]: value }));
    };

    const filteredData = useMemo(() => {
        return masterData.filter(item => {
            return (
                (filters.tenCoSo ? item.tenCoSo?.toLowerCase().includes(filters.tenCoSo.toLowerCase()) : true) &&
                (filters.tinhThanhPho ? item.tinhThanhPho?.toLowerCase().includes(filters.tinhThanhPho.toLowerCase()) : true) &&
                (filters.tenLamSan ? item.tenLamSan?.toLowerCase().includes(filters.tenLamSan.toLowerCase()) : true) &&
                (filters.trangThai ? item.trangThai === filters.trangThai : true)
            );
        });
    }, [filters, masterData]);

    if (loading) return <p>Đang tải dữ liệu, vui lòng chờ...</p>;

    return (
        <div className="master-list-container">
            <h1>Bảng tổng hợp Lâm sản và Cơ sở</h1>

            <div className="filters-panel">
                <input type="text" name="tenCoSo" placeholder="Lọc theo tên cơ sở..." onChange={handleFilterChange} />
                <input type="text" name="tinhThanhPho" placeholder="Lọc theo tỉnh (TP)..." onChange={handleFilterChange} />
                <input type="text" name="tenLamSan" placeholder="Lọc theo tên lâm sản..." onChange={handleFilterChange} />
                <select name="trangThai" onChange={handleFilterChange}>
                    <option value="">Tất cả trạng thái</option>
                    <option value="Đang hoạt động">Đang hoạt động</option>
                    <option value="Đã đóng cửa">Đã đóng cửa</option>
                    <option value="Tạm dừng">Tạm ngưng</option>
                </select>
            </div>

            <div className="table-wrapper">
                <table className="master-table">
                    <thead>
                        <tr>
                            {/* Phần Lâm sản */}
                            <th>Tên Lâm sản</th>
                            <th>Khối lượng</th>
                            <th>Đơn vị</th>
                            <th>Nguồn gốc Gỗ</th>
                            {/* Phần Cơ sở (lấy từ KhaiBaoCoSo.js) */}
                            <th>Tên Cơ sở</th>
                            <th>Tỉnh (TP)</th>
                            <th>Địa chỉ</th>
                            <th>Trạng thái</th>
                            <th>Người đại diện</th>
                            <th>Số CCCD</th>
                            <th>Ngày thành lập</th>
                            {/* Thêm các cột khác nếu cần */}
                        </tr>
                    </thead>
                    <tbody>
                        {filteredData.map(item => (
                            <tr key={item._id}>
                                {/* Dữ liệu Lâm sản */}
                                <td className="highlight-col">{item.tenLamSan}</td>
                                <td>{item.khoiLuong}</td>
                                <td>{item.donViTinh}</td>
                                <td>{item.nguonGocGo}</td>
                                {/* Dữ liệu Cơ sở */}
                                <td className="highlight-col">{item.tenCoSo}</td>
                                <td>{item.tinhThanhPho}</td>
                                <td>{item.diaChiCoSo}</td>
                                <td>{item.trangThai}</td>
                                <td>{item.tenNguoiDaiDien}</td>
                                <td>{item.soCCCD}</td>
                                <td>{item.ngayThanhLap ? new Date(item.ngayThanhLap).toLocaleDateString() : ''}</td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
             {filteredData.length === 0 && !loading && <p>Không tìm thấy dữ liệu phù hợp.</p>}
        </div>
    );
}

export default MasterProductListPage;
